M&\text{if failure and UW not active},\\
0&\text{if no failure}.\end{cases}

\Delta W=\begin{cases}\Pi-\max(0,\;M-D)&\text{if UW active and failure},\\
\Pi&\text{if UW active and no failure},\\
0&\text{otherwise}.\end{cases}
